import networkx as nx

def maximum_independent_set(edge_list, config=None):
    G = nx.Graph()
    G.add_edges_from(edge_list)
    seed = None
    if isinstance(config, dict):
        seed = config.get('seed')
    try:
        result = nx.approximation.maximum_independent_set(G, seed=seed) if seed is not None else nx.approximation.maximum_independent_set(G)
    except TypeError:
        result = nx.approximation.maximum_independent_set(G)
    return len(list(result))```
